#nullable enable // autogenerated

using MVZ2.GameContent.Models;
using MVZ2.GameContent.Seeds;
using MVZ2.Vanilla.Models;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Models;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Level;
using PVZEngine.Modifiers;
using Tools;

namespace MVZ2.GameContent.Buffs.SeedPacks
{
    [AutoBuffDefinition(VanillaBuffNames.SeedPack.blueprintLock)]
    public class BlueprintLockBuff : BuffDefinition
    {
        public BlueprintLockBuff(string nsp, string name) : base(nsp, name)
        {
            AddModelInsertion(LogicModelHelper.ANCHOR_CENTER, VanillaModelKeys.blueprintLock, VanillaModelID.blueprintLock);
            AddModifier(new NamespaceIDModifier(EngineSeedProps.DISABLE_ID, SetOperator.Set, VanillaBlueprintErrors.locked));
        }
        public override void OnCreate(Buff buff)
        {
            base.OnCreate(buff);
            SetTimer(buff, TimerHelper.NewSecondTimer(LOCK_TIME_SECONDS));
        }
        public override void PostUpdate(Buff buff)
        {
            base.PostUpdate(buff);
            var timer = GetTimer(buff);
            if (timer.RunToExpiredOrNull())
            {
                buff.Remove();
            }
        }
        public static FrameTimer? GetTimer(Buff buff) => buff.GetProperty<FrameTimer>(PROP_TIMER);
        public static void SetTimer(Buff buff, FrameTimer? value) => buff.SetProperty(PROP_TIMER, value);
        public const float LOCK_TIME_SECONDS = 30f;
        public static readonly VanillaBuffPropertyMeta<FrameTimer> PROP_TIMER = new VanillaBuffPropertyMeta<FrameTimer>("timer");
    }
}
